function setMarketplaceSettingAddress(address _marketplaceSetting) external {
    require(msg.sender == IMarketplaceSetting(marketplaceSetting).s2Admin(), "SS_Marketplace: Unauthorized user");
    require(_marketplaceSetting != address(0), "SS_Marketplace: Address cannot be null");
    marketplaceSetting = _marketplaceSetting;
}

function completePurchase(address buyer, address vesting, uint256 amount) external onlyMarketplace {
    allocations[buyer][vesting].bought += amount;
    SecondSwap_Vesting(vesting).transferVesting(address(this), buyer, amount);
}

function setManager(address _vestingManager) external onlyAdmin {
    require(_vestingManager != address(0), "SS_Marketplace_Settings: Cannot be zero address");
    require(
        _vestingManager != address(vestingManager),
        "SS_Marketplace_Settings: Cannot be the same vestingManager address"
    );
    vestingManager = _vestingManager;
}
